select r.role_code, r.role_type, g.* from app_auth_role r left join app_auth_data_group g on r.application_id = g.application_id and r.id = g.role_id where r.deleted = 0 and (g.deleted = 0 or g.deleted is null) and r.application_id = #{applicationId} and r.id in
#{item}
and (g.menu_id = #{menuId} or g.menu_id is null)
